6	/// resolve weights through mlx-audio's `ModelUtils.resolveOrDownloadModel`, which uses the
7	/// same `<cache>/mlx-audio/<modelID-with-slashes-replaced-by-underscores>/` convention, so
8	/// path resolution is family-agnostic.
9	enum ASRRuntimeFactory {
10	    static func make(profile: ModelProfile, cacheDirectory: URL?) -> any ASRRuntime {
11	        switch profile.family {
12	        case .qwen3:
13	            return MLXAudioQwenRuntime(modelID: profile.modelID, cacheDirectory: cacheDirectory)
14	        case .whisper:
15	            return MLXAudioWhisperRuntime(modelID: profile.modelID, cacheDirectory: cacheDirectory)
16	        }
17	    }
18	
19	    static func snapshotDirectory(for modelID: String, cache: HubCache) -> URL {
20	        let subdir = modelID.replacingOccurrences(of: "/", with: "_")
21	        return cache.cacheDirectory
22	            .appendingPathComponent("mlx-audio")
23	            .appendingPathComponent(subdir)
24	    }
25	
26	    /// Heuristic shared with both runtimes: a snapshot directory is "downloaded" once any
27	    /// `*.safetensors` weight file is present. mlx-audio downloads weights last so partial
28	    /// downloads don't trip this check.
29	    static func hasModelFiles(in directory: URL) -> Bool {
30	        let fm = FileManager.default
31	        guard fm.fileExists(atPath: directory.path),
32	              let enumerator = fm.enumerator(at: directory, includingPropertiesForKeys: nil) else {
33	            return false
34	        }
35	        for case let url as URL in enumerator {
36	            if url.pathExtension == "safetensors" { return true }
37	        }
38	        return false
39	    }
40	
