42	        let fm = FileManager.default
43	        guard fm.fileExists(atPath: url.path),
44	              let enumerator = fm.enumerator(at: url, includingPropertiesForKeys: [.totalFileAllocatedSizeKey, .fileSizeKey]) else {
45	            return 0
46	        }
47	        var total: Int64 = 0
48	        for case let entry as URL in enumerator {
49	            let values = try? entry.resourceValues(forKeys: [.totalFileAllocatedSizeKey, .fileSizeKey])
50	            total += Int64(values?.totalFileAllocatedSize ?? values?.fileSize ?? 0)
51	        }
