3	/// Minimal Hugging Face Hub API client just to fetch repo file sizes so we can
4	/// compute download progress percentages locally.
5	enum HuggingFaceMetadata {
6	    private struct TreeEntry: Decodable {
7	        let path: String
8	        let type: String
9	        let size: Int64?
10	        let lfs: LFS?
11	
12	        struct LFS: Decodable {
13	            let size: Int64?
14	        }
15	
16	        var effectiveSize: Int64 {
17	            lfs?.size ?? size ?? 0
18	        }
19	    }
20	
21	    /// Sum the byte sizes of all files in the repository's `main` revision.
22	    /// Returns `nil` on network or parse errors so callers can fall back to
23	    /// progress-without-total UI.
